void main(void) {
    volatile signed char   sc = (signed char)0xFF;
    volatile unsigned char uc = (unsigned char)0xFF;

    int s_widened = sc;
    int u_widened = uc;

    __CPROVER_assert(s_widened == -1, "trap reachable for signed char");
    __CPROVER_assert(u_widened == 255, "trap reachable for unsigned char");
}
